class Solution:
    def maxFreq(self, s, maxLetters, minSize, maxSize):
        from collections import Counter
        n = len(s)
        if minSize > n:
            return 0
        freq = Counter()
        for i in range(0, n - minSize + 1):
            sub = s[i:i + minSize]
            if len(set(sub)) <= maxLetters:
                freq[sub] += 1
        return max(freq.values()) if freq else 0

