var maxFreq = function(s, maxLetters, minSize, maxSize) {
    const n = s.length;
    if (minSize > n) return 0;
    const freq = new Map();
    let best = 0;
    for (let i = 0; i + minSize <= n; i++) {
        const sub = s.slice(i, i + minSize);
        if (new Set(sub).size <= maxLetters) {
            const c = (freq.get(sub) || 0) + 1;
            freq.set(sub, c);
            if (c > best) best = c;
        }
    }
    return best;
};
